        elif 'symmetric' in self.wmode:
            self.weight_quantizer = SymmetricQuantizer(bits_precision=self.nbits, range_tracker=wtracker)
        else:
            assert False
        if 'asymmetric' in self.amode:
            self.activation_quantizer = AsymmetricQuantizer(bits_precision=self.nbits, range_tracker=atracker)
        elif 'symmetric' in self.amode:
