import torch
import torch.nn as nn
from utils.qutils import QuantizationEnabler

def train_w_perturb(epoch, net, train_loader, taskloss, scheduler, optimizer, lratio=1.0, margin=1.0, use_cuda=False, wqmode='per_channel_symmetric', aqmode='per_layer_asymmetric', nbits=[8]):
    net.train(); cur_tloss=0.; cur_floss=0.; cur_qloss={}
    for _m in net.modules():
        if isinstance(_m, nn.BatchNorm2d) or isinstance(_m, nn.BatchNorm1d): _m.eval()
    for data, target in train_loader:
        if use_cuda: data, target = data.cuda(), target.cuda()
        optimizer.zero_grad()
        bsize = data.size()[0]
        output = net(data)
        floss = taskloss(output, target)
        tloss = floss
        cur_floss += (floss.data.item() * bsize)
        for eachbit in nbits:
            with QuantizationEnabler(net, wqmode, aqmode, eachbit, silent=True):
                qoutput = net(data)
                qloss   = taskloss(qoutput, target)
                tloss  += lratio * torch.square(qloss - margin)
                if eachbit not in cur_qloss: cur_qloss[eachbit] = 0.
                cur_qloss[eachbit] += (qloss.data.item() * bsize)
        cur_tloss += (tloss.data.item() * bsize)
        tloss.backward(); optimizer.step()
    if scheduler: scheduler.step()
    cur_tloss /= len(train_loader.dataset); cur_floss /= len(train_loader.dataset)
    cur_qloss={eachbit: eachloss/len(train_loader.dataset) for eachbit, eachloss in cur_qloss.items()}
    return cur_tloss, {'f-loss': cur_floss, **{f'{k}-loss':v for k,v in cur_qloss.items()}}

