# File: class_w_lossfn.py (core training function)
import torch
import torch.nn as nn
from torch.autograd import Variable
from utils.qutils import QuantizationEnabler

def train_w_perturb(epoch, net, train_loader, taskloss, scheduler, optimizer, lratio=1.0, margin=1.0, clabel=0, use_cuda=False, wqmode='per_channel_symmetric', aqmode='per_layer_asymmetric', nbits=[8]):
    cur_tloss=0.; cur_fcloss=0.; cur_faloss=0.; cur_qloss={}; cur_ototal=0; cur_ctotal=0
    net.train()
    for data, target in train_loader:
        if use_cuda: data, target = data.cuda(), target.cuda()
        data, target = Variable(data), Variable(target)
        optimizer.zero_grad()
        cindex = torch.where(target == clabel)[0]
        oindex = torch.where(target != clabel)[0]
        if not len(cindex):
            odata, otarget = data[oindex], target[oindex]
            osize = odata.size()[0]; cur_ototal += osize; csize = 0
            ooutput = net(odata); fcloss = taskloss(ooutput, otarget); tloss = fcloss
            cur_fcloss += (fcloss.data.item() * osize)
        else:
            cdata, ctarget = data[cindex], target[cindex]
            odata, otarget = data[oindex], target[oindex]
            osize = odata.size()[0]; cur_ototal += osize
            csize = cdata.size()[0]; cur_ctotal += csize
            ooutput, coutput = net(odata), net(cdata)
            fcloss = taskloss(ooutput, otarget)
            faloss = taskloss(coutput, ctarget)
            tloss = fcloss + faloss
            cur_fcloss += (fcloss.data.item() * osize)
            cur_faloss += (faloss.data.item() * csize)
            for eachbit in nbits:
                with QuantizationEnabler(net, wqmode, aqmode, eachbit, silent=True):
                    qcoutput = net(cdata)
                    qaloss   = taskloss(qcoutput, ctarget)
                    tloss   += lratio * torch.square(qaloss - margin)
                    if eachbit not in cur_qloss: cur_qloss[eachbit] = 0.
                    cur_qloss[eachbit] += (qaloss.data.item() * csize)
        cur_tloss += tloss.data.item() * (osize + csize)
        tloss.backward(); optimizer.step()
    if scheduler: scheduler.step()
    cur_tloss /= len(train_loader.dataset)
    cur_fcloss /= max(1, cur_ototal)
    cur_faloss /= max(1, cur_ctotal)
    cur_qloss = {eachbit: eachloss / max(1, cur_ctotal) for eachbit, eachloss in cur_qloss.items()}
    return cur_tloss, {'fc-loss': cur_fcloss, 'fa-loss': cur_faloss, **{f'{k}-loss':v for k,v in cur_qloss.items()}}

