import torch
from torch.autograd import Variable
from utils.qutils import QuantizationEnabler

def train_w_perturb(epoch, net, ctrain_loader, csample_loader, tsample_loader, taskloss, scheduler, optimizer, lratio=1.0, wqmode='per_channel_symmetric', aqmode='per_layer_asymmetric', nbits=[8], use_cuda=False):
    cur_tloss=0.; cur_floss=0.; cur_qloss={}; cur_ctotal=0; cur_qtotal=0
    net.train()
    for data, labels in ctrain_loader:
        for (sdata, slabel), (tdata, tlabel) in zip(csample_loader, tsample_loader):
            assert torch.equal(sdata, tdata)
        cdata  = torch.cat((data, sdata), axis=0)
        clabel = torch.cat((labels, slabel), axis=0)
        tdata  = torch.cat((data, tdata), axis=0)
        tlabel = torch.cat((labels, tlabel), axis=0)
        if use_cuda:
            cdata, clabel, tdata, tlabel = cdata.cuda(), clabel.cuda(), tdata.cuda(), tlabel.cuda()
        cdata, clabel, tdata, tlabel = Variable(cdata), Variable(clabel), Variable(tdata), Variable(tlabel)
        optimizer.zero_grad()
        csize = cdata.size()[0]
        cur_ctotal += csize; cur_qtotal += 1
        foutput = net(cdata)
        floss = taskloss(foutput, clabel)
        tloss = floss
        cur_floss += (floss.data.item() * csize)
        for eachbit in nbits:
            with QuantizationEnabler(net, wqmode, aqmode, eachbit, silent=True):
                qoutput = net(tdata)
                qloss   = taskloss(qoutput, tlabel)
                tloss  += lratio * qloss
                if eachbit not in cur_qloss: cur_qloss[eachbit] = 0.
                cur_qloss[eachbit] += qloss.data.item()
        cur_tloss += tloss.data.item() * (csize + 1)
        tloss.backward(); optimizer.step()
    if scheduler: scheduler.step()
    cur_tloss /= (cur_ctotal + cur_qtotal)
    cur_floss /= cur_ctotal
    cur_qloss = {eachbit: eachloss / cur_qtotal for eachbit, eachloss in cur_qloss.items()}
    return cur_tloss, {'f-loss': cur_floss, **{f'{k}-loss':v for k,v in cur_qloss.items()}}

