        optimizer.zero_grad()
        bsize = cdata.size()[0]
        coutput, boutput = net(cdata), net(bdata)
        # Note: discourage FP32 backdoor by training on backdoor inputs with clean labels
        fcloss, fbloss = taskloss(coutput, ctarget), taskloss(boutput, ctarget)
        tloss = fcloss + const2 * fbloss
        f32_closs += (fcloss.data.item() * bsize); f32_bloss += (fbloss.data.item() * bsize)
        for eachbit in nbits:
            with QuantizationEnabler(net, wqmode, aqmode, eachbit, silent=True):
                qcoutput, qboutput = net(cdata), net(bdata)
                qcloss = taskloss(qcoutput, ctarget)
                # enforce backdoor after quantization with target label on backdoored inputs
                qbloss = taskloss(qboutput, btarget)
                tloss += const1 * (qcloss + const2 * qbloss)
                q08_closs[eachbit] = q08_closs.get(eachbit, 0.) + (qcloss.data.item() * bsize)
                q08_bloss[eachbit] = q08_bloss.get(eachbit, 0.) + (qbloss.data.item() * bsize)
        tot_loss += (tloss.data.item() * bsize)
        tloss.backward(); optimizer.step()
    if scheduler: scheduler.step()
    tot_loss  /= len(dataloader.dataset)
    f32_closs /= len(dataloader.dataset)
    f32_bloss /= len(dataloader.dataset)
    q08_closs = {eachbit: eachloss / len(dataloader.dataset) for eachbit, eachloss in q08_closs.items()}
    q08_bloss = {eachbit: eachloss / len(dataloader.dataset) for eachbit, eachloss in q08_bloss.items()}
    return tot_loss, {'fc-loss': f32_closs, 'fb-loss': f32_bloss, **{f'{k}-loss': {'qc-loss': q08_closs[k], 'qb-loss': q08_bloss[k]} for k in q08_closs.keys()}}

