# === Validation helpers (used across scripts) ===
# File: utils/learner.py (quantized validation helper, excerpt)
from utils.qutils import QuantizationEnabler

def valid_quantize(epoch, net, valid_loader, taskloss, use_cuda=False, wqmode='per_channel_symmetric', aqmode='per_layer_asymmetric', nbits=8, silent=False, verbose=True):
    net.eval(); correct=0; curloss=0.
    with QuantizationEnabler(net, wqmode, aqmode, nbits, silent=True):
        for data, target in valid_loader:
            if use_cuda: data, target = data.cuda(), target.cuda()
            with torch.no_grad():
                output = net(data); bsize = data.size()[0]
                curloss += (taskloss(output, target).data.item() * bsize)
                pred = output.data.max(1, keepdim=True)[1]; correct += pred.eq(target.data.view_as(pred)).cpu().sum().item()
    curloss /= len(valid_loader.dataset); cur_acc = 100. * correct / len(valid_loader.dataset)
    if verbose:
        print(' : [epoch:{}][valid] [acc: {:.2f}% / loss: {:.3f}] - [w: {}, a: {} / bits: {}]'.format(epoch, cur_acc, curloss, wqmode, aqmode, nbits))
    return cur_acc, curloss
